import classnames from 'classnames';
import { FC, useEffect, useState } from 'react';

import {
  CLASS_OVERLAY_BACKGROUND,
  CLASS_OVERLAY,
  CLASS_OVERLAY_OPEN,
  CLASS_OVERLAY_BACKGROUND_OPEN,
} from './Overlay.constants';
import { Background } from './Overlay.styles';
import { OverlayProps } from './Overlay.types';

// closing this overlay can also happen when the escape key is pressed,
// this is managed with a global 'keydown' event listener that is contained
// within ArchipelagoProvider.js
const Overlay: FC<OverlayProps> = ({
  children,
  isHidden = true,
  returnFocus,
  onBackgroundClick,
  Wrapper,
  className,
  ...rest
}) => {
  const [isTriggered, setIsTriggered] = useState(false);
  const backgroundClassName = isHidden ? '' : CLASS_OVERLAY_BACKGROUND_OPEN;
  const wrapperClassName = isHidden ? '' : CLASS_OVERLAY_OPEN;

  /* When it opens, set focus to the first button in the Lightbox, which should
  be the close button. When it closes, refocus back on whatever element you
  specify. */
  useEffect(() => {
    if (!isHidden) {
      if (className) {
        const nodes = document.querySelectorAll(`.${className} button`);
        if (nodes.length) {
          (nodes[0] as HTMLElement)?.focus();
        } else {
          console.error('No overlay buttons detected');
        }
      } else {
        console.error('No overlay class name specified');
      }
      document.body.style.height = '100vh';
      document.body.style.overflow = 'hidden';
      setIsTriggered(true);
    } else if (isTriggered) {
      (document.querySelector(returnFocus) as HTMLElement)?.focus();
      document.body.style.height = '';
      document.body.style.overflow = '';
      setIsTriggered(false);
    }
  }, [isHidden, isTriggered, returnFocus, className]);

  return (
    <>
      <Background
        aria-hidden={isHidden}
        className={classnames(CLASS_OVERLAY_BACKGROUND, backgroundClassName)}
        $isHidden={isHidden}
        onClick={onBackgroundClick}
      />
      <Wrapper
        aria-hidden={isHidden}
        className={classnames(CLASS_OVERLAY, wrapperClassName, className)}
        $isHidden={isHidden}
        {...rest}
      >
        {children}
      </Wrapper>
    </>
  );
};

export default Overlay;
